create table dirkspzm32.pzm_ze_loa_statistik_exp_host (
    pb_id                number(*, 0) not null enable,
    pers_nr              number(*, 0) not null enable,
    datum                date not null enable,
    stat_value           number not null enable,
    stat_unit            varchar2(50 char),
    status               varchar2(3 char),
    ret_code             varchar2(20 char),
    err_text             varchar2(1024 char),
    cycle                number,
    kst_id               number(*, 0) not null enable,
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    created_user         varchar2(255 char),
    last_change_date     date,
    last_change_login_id number(*, 0),
    last_change_user     varchar2(255 char)
);

alter table dirkspzm32.pzm_ze_loa_statistik_exp_host
    add constraint pk_pzm_ze_loa_statistik_exp_host
        primary key ( pb_id,
                      pers_nr,
                      datum,
                      stat_unit )
            using index enable;


